<?php include 'header.php'; $id=intval($_GET['id']??0); $stmt=$pdo->prepare('SELECT * FROM products WHERE id=?'); $stmt->execute([$id]); $p=$stmt->fetch(); if(!$p){echo "<section class='section'><h2>Product not found.</h2></section>"; include 'footer.php'; exit;} if($_SERVER['REQUEST_METHOD']==='POST'){ $qty=max(1,intval($_POST['quantity'])); $_SESSION['cart'][$id]=($_SESSION['cart'][$id]??0)+$qty; header('Location: cart.php'); exit;} ?>
<section class="product-page"><img src="<?= htmlspecialchars($p['image']); ?>"><div><p class="badge"><?= htmlspecialchars(str_replace('_',' ',$p['category'])); ?></p><h1><?= htmlspecialchars($p['name']); ?></h1><h3><?= htmlspecialchars($p['brand']); ?></h3><p><?= nl2br(htmlspecialchars($p['description'])); ?></p><h2>$<?= number_format($p['price'],2); ?></h2><p>Available stock: <?= $p['stock']; ?></p><form method="POST" class="qty-form"><input type="number" name="quantity" value="1" min="1" max="<?= $p['stock']; ?>"><button class="btn">Add to Cart</button></form></div></section><?php include 'footer.php'; ?>
